#include<bits/stdc++.h>
using namespace std;
bool vis[1000010];
long long a[1000010],b[1000010],c[1000010],d[1000010],m[1000010];
int main()
{
    long long n;
    scanf("%lld",&n);
    long long min1=INT_MAX;
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&m[i]);
        min1=min(min1,m[i]);
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        d[a[i]]=i;
    }
    for(long long i=1;i<=n;i++)
    {
        c[i]=m[a[i]];
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
        b[i]=d[b[i]];
    }
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        if(!vis[i])
        {
            long long sum=0,min2=INT_MAX,cnt=0;
            while(!vis[i])
            {
                min2=min(min2,c[i]);
                vis[i]=1;
                sum+=c[i];
                cnt++;
                i=b[i];
            }
            ans+=min(min2*(cnt-1)+(sum-min2),(min1+min2)*2+min1*(cnt-1)+(sum-min2));
        }
    }
    printf("%lld",ans);
    return 0;
}
